  ('disabled-704caaf1-moex-00005', 'disabled-704caaf1', 'disabled-704caaf1-moex-114-decd973b', 'sub-disabled-704caaf1-02', NULL, 'single_choice', '依憲法第1條，我國之國家形式為共和國，其特徵為何？', '["憲政體制為總統制", "國會為兩院制", "國家元首由選舉產生且有一定任期", "國家元首即國家最高行政首長"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:42+00:00", "source_pdf_sha1": "285bae6995ae", "answer_pdf_sha1": "96a597fd4e3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "412", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "衛生技術"}'::jsonb, NULL),
  ('disabled-704caaf1-moex-00006', 'disabled-704caaf1', 'disabled-704caaf1-moex-114-decd973b', 'sub-disabled-704caaf1-02', NULL, 'single_choice', '依據憲法增修條文規定，國家對於社會救助和國民就業等救濟性支出，在 編列預算時應為如何之處理？', '["應優先編列", "應逐年增加預算", "不得少於預算總額百分之二十", "憲法增修條文對此並無規定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:42+00:00", "source_pdf_sha1": "285bae6995ae", "answer_pdf_sha1": "96a597fd4e3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "412", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "衛生技術"}'::jsonb, NULL),
  ('disabled-704caaf1-moex-00007', 'disabled-704caaf1', 'disabled-704caaf1-moex-114-decd973b', 'sub-disabled-704caaf1-02', NULL, 'single_choice', '依司法院大法官解釋，有關集會遊行自由，下列敘述何者錯誤？', '["於集會遊行中不得高舉主張共產主義之標語", "於集會遊行中不得攜帶刀械棍棒", "主管機關不得僅因申請遊行團體主張分裂國土即不予許可", "偶發性之集會遊行不受事前申請之限制"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:42+00:00", "source_pdf_sha1": "285bae6995ae", "answer_pdf_sha1": "96a597fd4e3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "412", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "衛生技術"}'::jsonb, NULL),
  ('disabled-704caaf1-moex-00008', 'disabled-704caaf1', 'disabled-704caaf1-moex-114-decd973b', 'sub-disabled-704caaf1-02', NULL, 'single_choice', '依司法院釋字第 468 號，有關總統副總統選舉罷免，下列敘述何者錯誤？', '["總統副總統選舉罷免法規定之連署制度，可表達被連署人有相當程度之 政治支持，藉與政黨推薦候選人之要件相平衡，並防止耗費社會資源", "連署人數達到法定人數2分之1以上時，保證金即予發還，並非對總統、 副總統被選舉權之不當限制，保證金額亦未逾越立法裁量範圍", "總統副總統選舉連署及查核辦法中，關於書件不全、不符規定或保證金 不足者，中選會應拒絕受理其申請之規定，業已違反比例原則", "立法機關得制定法律，就總統、副總統之選舉程序，為公平合理之規範； 如未逾越必要限制，即不侵害憲法上保障之選舉權及被選舉權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:42+00:00", "source_pdf_sha1": "285bae6995ae", "answer_pdf_sha1": "96a597fd4e3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "412", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "衛生技術"}'::jsonb, NULL),
  ('disabled-704caaf1-moex-00009', 'disabled-704caaf1', 'disabled-704caaf1-moex-114-decd973b', 'sub-disabled-704caaf1-02', NULL, 'single_choice', '依司法院釋字第 490 號，兵役法所定服兵役義務與憲法第 13 條保障宗教 信仰自由之意旨相符，下列敘述何者錯誤？', '["兵役法規定係為實踐憲法上人民之基本義務", "為保障人民之宗教信仰自由，立法者應設置替代役制度", "服兵役義務規定非為助長、促進或限制宗教而設", "服兵役義務之目的係為保護人民，防衛國家之安全"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:42+00:00", "source_pdf_sha1": "285bae6995ae", "answer_pdf_sha1": "96a597fd4e3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "412", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "衛生技術"}'::jsonb, NULL),
  ('disabled-704caaf1-moex-00010', 'disabled-704caaf1', 'disabled-704caaf1-moex-114-decd973b', 'sub-disabled-704caaf1-02', NULL, 'single_choice', '司法院大法官解釋或憲法法庭判決已經承認之憲法第 22 條非明文權利， 不包括下列何者？', '["受國民教育以外教育之權利", "罹患重症末期瀕死，痛苦難以忍受之病人，請求醫師協助終止生命之 權利", "同性別二人成立排他永久親密關係之權利", "原住民依據所屬之民族、部落傳統，從事狩獵之權利"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:42+00:00", "source_pdf_sha1": "285bae6995ae", "answer_pdf_sha1": "96a597fd4e3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "412", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "衛生技術"}'::jsonb, NULL),
  ('disabled-704caaf1-moex-00011', 'disabled-704caaf1', 'disabled-704caaf1-moex-114-decd973b', 'sub-disabled-704caaf1-02', NULL, 'single_choice', '大學生受憲法保障之受教育權，係源自於憲法那一條之規定？', '["憲法第22條之非明文權利", "憲法第21條之受國民教育權", "憲法第15條之工作權", "憲法第11條之學習自由"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:42+00:00", "source_pdf_sha1": "285bae6995ae", "answer_pdf_sha1": "96a597fd4e3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "412", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "衛生技術"}'::jsonb, NULL),
  ('disabled-704caaf1-moex-00012', 'disabled-704caaf1', 'disabled-704caaf1-moex-114-decd973b', 'sub-disabled-704caaf1-02', NULL, 'single_choice', '依司法院大法官解釋及憲法法庭判決，下列何者並非立法院之職權範圍？', '["制定法律規定公務員免職事由及其應遵循之正當法律程序，並給予被免 職之公務員得依法請求司法救濟", "對於重大政策之爭議，認為有由人民直接決定之必要者，得制定法律， 交付公民投票", "立法規定獨立行政機關之人事提名，由立法院各政黨（團）依其在立法 院所占席次比例推薦產生", "邀請參謀總長到立法院委員會備詢"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:42+00:00", "source_pdf_sha1": "285bae6995ae", "answer_pdf_sha1": "96a597fd4e3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "412", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "衛生技術"}'::jsonb, NULL),
  ('disabled-704caaf1-moex-00013', 'disabled-704caaf1', 'disabled-704caaf1-moex-114-decd973b', 'sub-disabled-704caaf1-02', NULL, 'single_choice', '依司法院大法官解釋及憲法法庭判決意旨，下列何者非屬對人民職業選擇 自由所為之主觀條件限制？', '["大學教師因未通過評鑑，而遭受不予續聘或資遣等決定", "公務員於其離職後3年內，不得擔任與其離職前5年內之職務直接相關 之營利事業董事", "計程車駕駛人於執業期中犯特定之罪而經法院判決有期徒刑以上之刑 確定者，廢止其職業登記", "禁止非視障者從事按摩業"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:42+00:00", "source_pdf_sha1": "285bae6995ae", "answer_pdf_sha1": "96a597fd4e3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "412", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "衛生技術"}'::jsonb, NULL),
  ('disabled-704caaf1-moex-00014', 'disabled-704caaf1', 'disabled-704caaf1-moex-114-decd973b', 'sub-disabled-704caaf1-02', NULL, 'single_choice', '依司法院大法官解釋意旨，下列關於居住自由及遷徙自由之敘述，何者 錯誤？', '["居住及遷徙之自由，旨在保障人民有自由設定住居所、遷徙、旅行，以 及出境或入境之權利", "對人民遷徙自由之限制，可以視規範對象是否為臺灣地區有戶籍人民、 僑居國外或居住港澳等地區之人民，而有不同差別之對待", "對於人民遷徙自由之限制事關重大，必須由法律自行規定，不得授權由 行政機關以行政命令定之", "警察執行臨檢勤務之處所如為私人居住之空間者，應受到與住宅相同之 保障"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:42+00:00", "source_pdf_sha1": "285bae6995ae", "answer_pdf_sha1": "96a597fd4e3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "412", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "衛生技術"}'::jsonb, NULL)
